INSERT INTO tours (
  title, slug, city, tag, subtitle, description, highlight,
  price, original_price, price_currency, price_type, image_url, gallery_images,
  duration, difficulty, group_size, lunch_included, ticket_included,
  pickup_info, notes, badges, highlights, includes, excludes,
  schedule, itinerary_details, faqs,
  rating, review_count, pickup_points_count, dropoff_points_count,
  is_active, is_featured, translations, seo_title, meta_description
) VALUES (
  'Jeju East Volcano, Coast & Village Small Group Tour',
  'east-signature-nature-core',
  'Jeju',
  'Small group · East Jeju',
  'A well-paced East Jeju route that begins with Jeju''s stone heritage and village culture, then opens into dramatic coastal scenery, Seongsan''s iconic views, and a refreshing beach finish.',
  'A balanced East Jeju course that moves naturally from Jeju''s cultural texture to its most iconic eastern coastal highlights.',
  'A classic East Jeju route designed to build gradually from calm cultural stops to the region''s most recognizable scenery.',
  58.00,
  72.00,
  'USD',
  'person',
  'https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=1200&q=85',
  '["https://images.unsplash.com/photo-1519681393784-d120267933ba?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1498654896293-37aacf113fd9?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&h=600&fit=crop"]'::jsonb,
  'Approx. 8 hours · East Jeju',
  'Moderate',
  'Small group',
  false,
  false,
  'The actual departure time may vary depending on pickup location and same-day road conditions. Final pickup guidance is provided after booking, with more specific instructions sent again the day before or the morning of the tour.',
  'WHAT TO WEAR / BRING: Comfortable shoes and a light outer layer; hat and sunglasses on sunny days; water; portable charger for photos.

WALKING / STAIRS: Not extreme overall, but the second half can feel more tiring than the first — especially Seopjikoji and Seongsan. Pace can be adjusted on site for parents or stamina concerns.

CHILDREN: Suited to families who enjoy scenic sightseeing; not a high-activity kids'' program.

SEASONAL — Spring: Often the most balanced season if wind is moderate. Summer: Flexible outdoor timing around heat and sun. Fall: Clear visibility and comfortable movement. Winter: Wind is the main variable; exposed stops may be shorter.

RAIN / WIND / PEAK SEASON: Coastal sections may become more viewpoint-based in rain; second half is wind-sensitive; on crowded days, efficient highlights beat long stays everywhere.

POST-BOOKING: We focus on pickup, movement, and day-of guidance that is genuinely useful — not only an itinerary PDF.

GOOD TO KNOW: Not a café-centered slow day; second half is more weather-exposed; order changes are on-site optimization.',
  '["First-Time Friendly","Scenic East Jeju","Balanced Day Flow","Culture to Coast","Family-Friendly","Weather-Aware Operation"]'::jsonb,
  '["Best for: First-time visitors to Jeju, couples, travelers with parents, and guests who want a balanced East Jeju route that includes culture, scenery, and iconic landmarks.","Not ideal for: Travelers who want a café-heavy day, a mostly indoor itinerary, or those who strongly prefer minimal outdoor walking.","Walking level: Moderate — Jeju Stone Park and Seongeup Folk Village are relatively comfortable; Seopjikoji and Seongsan can feel more demanding depending on distance, weather, and crowds.","Rain safety: Medium — not fully rain-proof, but usually operable by adjusting stay times and sequence.","Family fit: Good — scenic sightseeing rather than high-activity travel.","Senior fit: Good — exposed coastal sections can be shortened on the day if needed.","Scenic intensity: High — stone landscape and village atmosphere to coastal grassland, volcanic views, and a bright beach finish.","Photo value: High — several of East Jeju''s most photogenic signature points in one day.","Relaxation level: Medium — not rushed, but not a slow café-style day.","Outdoor / indoor balance: Mostly outdoors; calmer first half, stronger scenic second half.","Booking card summary: A first-time-friendly East Jeju course from Jeju Stone Park and Seongeup through Seopjikoji, Seongsan Ilchulbong, and a bright Hamdeok Beach finish.","Related: East Nature + Café Relax — scenic highlights with slower café pace. East Family & Rain-Safer — stronger indoor stability for families or rainy days."]'::jsonb,
  '["Practical guidance after booking — not only a confirmation","Final pickup information once details are confirmed","Reminder within 12 hours before the tour","Guidance for the first stop of the day","Clothing and weather tips","Short tips for each major stop","On-site updates if conditions require adjustments","Licensed professional guide (small group)","Round-trip transport for the scheduled route"]'::jsonb,
  '["Meals and drinks unless your booked fare states otherwise","Attraction entrance fees unless explicitly included in your fare","Personal expenses, tips, and travel insurance"]'::jsonb,
  '[{"time":"09:00","title":"Jeju Stone Park","description":"Calm opening — Jeju''s volcanic stone landscape and cultural identity."},{"time":"10:30","title":"Seongeup Folk Village","description":"Traditional village atmosphere — stone walls, thatched roofs, local character."},{"time":"12:15","title":"Lunch","description":"Midday reset before the major coastal highlights (meal per your fare)."},{"time":"13:30","title":"Seopjikoji","description":"Signature East Jeju coast — grassland, volcanic terrain, and open sea."},{"time":"15:00","title":"Seongsan Ilchulbong","description":"Iconic volcanic centerpiece of East Jeju — viewpoint or longer scenic stay depending on the day."},{"time":"16:45","title":"Hamdeok Beach","description":"Bright, relaxed beach finish — open shoreline and lighter mood."}]'::jsonb,
  '[{"time":"45–60 min","activity":"Jeju Stone Park","description":"A calm opening where Jeju''s volcanic stone landscape and cultural identity come into focus. Starting here gives a grounded beginning before the more dramatic coastal stops. Recommended stay 45–60 minutes. Walking: low to moderate — better for unhurried exploration. Photo tip: clean compositions with stone sculptures and open space. Restroom: available. Weather: easier than wind-exposed coasts; not fully indoors. If delayed: stay time can be shortened.","images":["https://images.unsplash.com/photo-1519681393784-d120267933ba?w=800&h=600&fit=crop"]},{"time":"35–50 min","activity":"Seongeup Folk Village","description":"Traditional village life and local atmosphere after the stone park — adds human texture so the first half feels layered, not repetitive. Recommended stay 35–50 minutes. Walking: low to moderate. Photo tip: thatched roofs and stone walls together capture the Jeju mood. Restroom: available. Weather: often still worthwhile in light rain; bring umbrella or raincoat. If delayed: can shorten to core sections only.","images":["https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800&h=600&fit=crop"]},{"time":"50–70 min","activity":"Lunch","description":"Midday break that resets rhythm before the exposed coastal second half. Restaurant may flex with route, waits, and guest preferences. Recommended stay 50–70 minutes. On rainy days, lunch doubles as a natural indoor rest.","images":["https://images.unsplash.com/photo-1498654896293-37aacf113fd9?w=800&h=600&fit=crop"]},{"time":"40–60 min","activity":"Seopjikoji","description":"One of East Jeju''s signature coastal highlights — grassland, volcanic ground, and sea together. Recommended stay 40–60 minutes. Walking: moderate; wind and distance affect fatigue. Photo tip: wide angles with grassland and coastline. Restroom: available. Weather: strong wind or rain may shorten the visit or shift to a viewpoint-style stop. If delayed: shorten when needed; skipping entirely is usually not recommended.","images":["https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800&h=600&fit=crop"]},{"time":"30–50 min","activity":"Seongsan Ilchulbong","description":"Symbolic centerpiece of East Jeju — one of the island''s most recognizable volcanic views. Recommended stay 30–50 minutes (viewpoint-focused or slightly longer scenic stay). Walking: low to moderate depending on how far guests explore. Photo tip: wide shot showing the Seongsan silhouette. Restroom: check nearby facilities. Weather: fog, wind, and crowds strongly affect the experience. If delayed: can compress to a shorter viewpoint visit.","images":["https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=800&h=600&fit=crop"]},{"time":"30–45 min","activity":"Hamdeok Beach","description":"Bright beach finish — open sea and a lighter, relaxed close to the day. Recommended stay 30–45 minutes. Walking: low along the beachfront. Photo tip: shoreline and sea color in wide compositions. Restroom: available. Weather: wind can drop felt temperature quickly; stay may be shortened. If delayed: easier to trim than core mid-route highlights.","images":["https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&h=600&fit=crop"]}]'::jsonb,
  '[{"question":"Is this course good for first-time visitors to Jeju?","answer":"Yes. It combines cultural atmosphere, East Jeju coastal scenery, and one of the island''s most iconic landmarks in one balanced route."},{"question":"Is the walking very difficult?","answer":"Not overall, but the second half can feel more tiring than the first, especially around Seopjikoji and Seongsan depending on weather and walking distance."},{"question":"Can the tour still run if it rains?","answer":"Yes. This is not a fully rain-specialized route, so stay times or order may be adjusted to protect on-the-day quality."},{"question":"Is it okay to join with parents?","answer":"Yes. The structure is generally comfortable, and exposed coastal sections can be shortened if needed."},{"question":"Can I join with children?","answer":"Yes. It is closer to scenic sightseeing than a high-activity family itinerary."},{"question":"Can the order change?","answer":"Yes. Coastal sections are sensitive to wind, traffic, and crowds; partial reordering can create a smoother flow — optimization, not a downgrade."},{"question":"Is lunch included?","answer":"That depends on the product setup; the route is designed with a meal break in the middle. Check your booking fare."},{"question":"Why start at Jeju Stone Park?","answer":"A calmer, more stable start. The route builds mood and scenery gradually instead of peaking immediately with open-sea views."},{"question":"Why is Seongeup placed next?","answer":"It adds traditional village texture after the stone landscape so the first half feels layered rather than one-note nature."},{"question":"Why is lunch placed there?","answer":"It resets energy before the more exposed and visually intense afternoon at Seopjikoji, Seongsan, and Hamdeok."},{"question":"Why is the later part structured this way?","answer":"Seopjikoji and Seongsan are signature highlights — grouping them focuses the scenic core of the day; Hamdeok releases intensity with a lighter finish."}]'::jsonb,
